#include<iostream>#include<algorithm>#include<cmath>#define ll long longusing namespace std;bool is_fair(ll n){    ll nums=n;    while(nums>0){        int x= nums%10;        if(x!=0 && n%x!=0) return false;        nums/=10;    }    return true;}int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        while(!is_fair(n)){            n++;        }        cout<<n<<"\n";    }}